VALUES
  ('heelevel3-c8735cdb-moex-00149', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '行政機關發現經其核准受領疫情紓困補助的受益人，有重複領取情形，於其撤銷原處分後，應採 取何種方式追回溢發之款項？', '["作成書面行政處分確認返還範圍，並限期命受益人返還", "向行政法院提起一般給付訴訟", "向民事法院提起請求返還不當得利訴訟", "直接移送法務部行政執行署所屬分署執行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00150', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '行政處分於法定救濟期間經過後，當事人仍得於一定情形下申請撤銷、廢止或變更之。下列敘述 何者錯誤？', '["具有持續效力之行政處分，其依據之事實事後發生有利變更者，相對人或利害關係人得提出申請", "該項申請應自法定救濟期間經過後3個月內為之", "雖有重新開始程序之原因，行政機關如認為原處分為正當者，仍應駁回該申請", "相對人或利害關係人因過失未能在行政程序中主張其事由者，即不得提出該項申請"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00151', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '有關行政契約，下列敘述何者錯誤？', '["行政程序法所規定的行政契約類型，有和解契約與雙務契約", "行政機關與人民締結行政契約後，為確保人民信賴利益，不得調整契約內容與終止契約", "行政契約之締結，原則上須以書面為之", "行政契約中，如行政機關與人民互負給付義務，雙方之給付應相當，且具備合理關聯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00152', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '下列何者屬於行政事實行為？', '["拆除違章建築", "行政院發布徵兵規則", "警察指揮交通", "行人穿越道之交通標線"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00153', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '藥事法規定不具藥商資格販賣藥品者，處新臺幣3萬元以上200萬元以下罰鍰。甲於網路上販售從 國外買回的藥品，被查獲違反前述藥事法規定，其請求依據行政罰法第19條規定免予處罰，承辦 此案之公務人員應如何處理？', '["若甲販賣藥品之獲利低於3萬元，得免予處罰", "若甲為初次違規，得免予處罰", "若藥品尚未售出，得免予處罰", "甲之情形無法適用行政罰法第19條免予處罰之規定 31550、31650 32250、32950 33050 33850"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00154', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '甲積欠交通違規罰單新臺幣18,000元，主管機關經催繳後仍未繳納，移送行政執行。依行政執行 法之規定，下列敘述何者正確？', '["如甲於執行程序終結前死亡，未留有遺產，執行機關應向甲之繼承人為執行", "如甲於執行程序終結前繳清罰鍰，其應以聲明異議之方式請求終止執行", "如執行機關發現甲顯有財產卻故意不繳納，且已出境1次，得限制甲之住居", "如甲對於執行機關限制住居之命令不服，經聲明異議遭駁回後，得直接提起撤銷訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00155', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '依據政府資訊公開法，關於政府資訊公開，下列敘述何者錯誤？', '["政府資訊可由政府機關主動公開，亦得應人民申請被動公開", "申請政府資訊之公開，不以主張或維護法律上利益有必要為前提", "對於政府資訊公開申請之決定不服者，得依法提起行政救濟", "經申請公開之政府資訊涉及第三人權益，經其明確表示不同意公開時，政府機關應即作成不予 公開之決定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00156', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '下列何者非訴願審理機關審理訴願案件應遵循之原則？', '["書面審查原則", "職權調查原則", "不利益變更禁止原則", "停止執行原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00157', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '軍校生甲，因行為失當，遭學校開除學籍。學校擬對甲求償已領取之公費，應循何種方式？', '["以行政處分令甲賠償", "直接依強制執行法聲請強制執行", "向行政法院提起一般給付之訴", "向民事法院提起訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00158', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '多數當事人關於訴訟標的之權利義務關係，在事實上或法律上有同一或同類原因時，有關訴訟程 序之敘述，下列何者錯誤？', '["可以成立共同訴訟，一同擔任原告或被告", "如果當事人分別起訴，法院得命其合併辯論及合併裁判", "共同訴訟之訴訟標的有合一確定必要時，共同訴訟人中一人不利於全體之行為，效力不及於全 體共同訴訟人", "共同訴訟之訴訟標的無論有無合一確定必要，當事人合意停止訴訟後，續行訴訟必須經全體同意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL)
